+    @Override
+    public void shutdown(JobStatus jobStatus, CheckpointsCleaner checkpointsCleaner)
+            throws Exception {
+        if (jobStatus.isGloballyTerminalState()) {
+            sharedStateRegistry.close();
+        }
+    }
